// Note: In main world, we can't import from other extension modules
// import { displayShellInjectionNotification } from './content-notifications.js';

import { MSG_SHELL_INJECTION_CLIPBOARD } from "@/app/scripts/app-consts";

//@ts-ignore
const useLogging = (ENVIRONMENT == "development");

export class ShellProtector {
    private static isActive = true;

    // Simplified version for main world - no extension APIs available
    static async allowScamsOnThisSite(): Promise<boolean> {
        // In main world, we can't communicate with extension directly
        // We'll use a custom event to communicate with the isolated world content script
        const event = new CustomEvent('mbg-allow-scams-on-site', {
            detail: { host: window.location.host }
        });
        window.dispatchEvent(event);
        return true;
    }

    // Attaches click events to disable warning buttons
    static attachEvents(dom: Document): void {
        const buttonIds = [
            "mb-disable-shell-warning",
            "mb-disable-search-hijacking-warning",
        ];

        buttonIds.forEach((id) => {
            const button = dom.getElementById(id);
            if (button) {
                button.addEventListener("click", async () => {
                    try {
                        await ShellProtector.allowScamsOnThisSite();
                        ShellProtector.isActive = false;
                        const root = document.getElementById("malwarebytes-root");
                        root?.remove();
                    } catch (error) {
                        useLogging && console.error("CONTENT_SHELL: Failed to disable warning", error);
                    }
                });
            }
        });
    }

    // Checks whether the current page is excluded - simplified for main world
    static async isExcluded(): Promise<boolean> {
        // Use custom event to check with isolated world content script
        return new Promise((resolve) => {
            const handleResponse = (event: CustomEvent) => {
                window.removeEventListener('mbg-exclusion-response', handleResponse as EventListener);
                resolve(!!event.detail?.excluded);
            };

            window.addEventListener('mbg-exclusion-response', handleResponse as EventListener);

            const event = new CustomEvent('mbg-check-exclusion', {
                detail: { type: "scam", url: window.location.href }
            });
            window.dispatchEvent(event);

            // Timeout fallback
            setTimeout(() => {
                window.removeEventListener('mbg-exclusion-response', handleResponse as EventListener);
                resolve(false);
            }, 1000);
        });
    }

    // Shell injection and command injection patterns
    // Network download commands using curl
    private static readonly curlPattern: RegExp = /\bcurl\s+(?:-[A-Za-z]+(?:\s+\S+)*)?(?:\s+)?(?:https?:|ftp:|\w+\.\w+(?:\/\S*)?)/gm;

    // Network download commands using wget
    private static readonly wgetPattern: RegExp = /\bwget\s+(?:-[A-Za-z-]+(?:\s+\S+)*)?(?:\s+)?(?:https?:|ftp:|\w+\.\w+(?:\/\S*)?|\S+\.(?:exe|sh|bat|ps1|vbs|hta))/gm;

    // Destructive or file-manipulation commands
    private static readonly destructiveCommandPattern: RegExp = /\b(?:rm\s+-[rfidR]|ls\s+-[A-Za-z]|cp\s+-[A-Za-z]|mv\s+-[A-Za-z])/gm;

    // File creation and directory navigation commands
    private static readonly fileAndDirectoryPattern: RegExp = /\b(?:touch\s+[\/."']|cd\s+[\/."'~])/gm;

    // Windows command interpreter and mshta calls
    private static readonly windowsExecutionPattern: RegExp = /\b(?:cmd(?:\s*\/[cCkK]|\.[eE][xX][eE])|mshta(?:\s*(?:https?:|file:)|\.[eE][xX][eE]))/gm;

    // Echo patterns commonly used to build commands or variable expansions
    private static readonly echoPattern: RegExp = /\becho\s+[$`(]/gm;

    // Grep with options (often used in command pipelines)
    private static readonly grepPattern: RegExp = /\bgrep\s+-[A-Za-z]/gm;

    // Command piping into shells
    private static readonly pipeToShellPattern: RegExp = /\|\s*(?:sh|bash|zsh|powershell)\b/gm;

    // Command chaining with semicolons followed by suspicious commands or options
    private static readonly commandChainingPattern: RegExp = /;\s*(?:\w+\s+-[A-Za-z]|curl|wget|rm|ls|cp|mv|touch|cd|cmd|mshta|echo|grep)\b/gm;

    // Subshells and command substitution patterns
    private static readonly subshellPattern: RegExp = /\$\(/gm;

    // Backtick-based command execution patterns
    private static readonly backtickPattern: RegExp = /`\(/gm;

    // Aggregate of all shell injection and command injection patterns
    private static readonly shellPatterns: RegExp[] = [
        ShellProtector.curlPattern,
        ShellProtector.wgetPattern,
        ShellProtector.destructiveCommandPattern,
        ShellProtector.fileAndDirectoryPattern,
        ShellProtector.windowsExecutionPattern,
        ShellProtector.echoPattern,
        ShellProtector.grepPattern,
        ShellProtector.pipeToShellPattern,
        ShellProtector.commandChainingPattern,
        ShellProtector.subshellPattern,
        ShellProtector.backtickPattern,
    ];

    // Checks if the given text matches any suspicious pattern
    static isSuspiciousText(text: string): boolean {
        // resetting lastIndex to 0 for global patterns https://developer.mozilla.org/en-US/docs/Web/JavaScript/Reference/Global_Objects/RegExp/lastIndex
        return this.shellPatterns.some((pattern) => {
            pattern.lastIndex = 0;
            return pattern.test(text);
        });
    }

    // Injects a warning into the DOM - simplified for main world
    static injectWarning(): void {
        // Send message to content script to check domain
        const hostname = window.location.hostname;
        if (!hostname) {
            return;
        }
        window.postMessage(
            {
                type: MSG_SHELL_INJECTION_CLIPBOARD,
                domain: hostname,
            },
            (window.location.origin || window.location.protocol + "//" + window.location.host)
        );
    }

    // Get clipboard content directly from the page context - no permissions needed!
    static async getClipboardContent(event: ClipboardEvent): Promise<string> {
        // 1. Try to get it from the event directly
        const fromEvent = (event.clipboardData && event.clipboardData.getData('text')) || window.getSelection()?.toString() || '';
        if (fromEvent && fromEvent.trim()) {
            return fromEvent;
        }

        // 2. In main world, we can access navigator.clipboard without permissions
        // if the user action triggered it (like copy event)
        try {
            const text = await navigator.clipboard.readText();
            if (text && text.trim()) {
                return text;
            }
        } catch (err) {
            useLogging && console.debug("getClipboardContent: navigator.clipboard.readText() failed", err);
        }

        // 3. Try navigator.clipboard.read() for richer clipboard access
        try {
            const items = await navigator.clipboard.read();
            for (const item of items) {
                if (item.types.includes("text/plain")) {
                    const blob = await item.getType("text/plain");
                    const blobText = await blob.text();
                    if (blobText?.trim()) {
                        return blobText;
                    }
                }
            }
        } catch (err) {
            useLogging && console.debug("getClipboardContent: navigator.clipboard.read() failed", err);
        }

        // 4. Fallback
        return "";
    }

    static async init(): Promise<void> {
        const excluded = await this.isExcluded();
        if (excluded) {
            useLogging && console.debug("CONTENT_SHELL: Page is excluded. Skipping shell protection.");
            return;
        }

        document.addEventListener("copy", async (event: ClipboardEvent) => {
            try {
                const clipboardText = await ShellProtector.getClipboardContent(event);
                const target = event.target as HTMLElement | null;
                const targetText = target?.innerText ?? "";

                let shouldWarn = ShellProtector.isSuspiciousText(clipboardText) || ShellProtector.isSuspiciousText(targetText);

                if (shouldWarn && ShellProtector.isActive) {
                    ShellProtector.injectWarning();
                }
            } catch (error) {
                useLogging && console.error("CONTENT_SHELL: Error handling copy event", error);
            }
        });

        // patch clipboard events to capture clipboard data
        const clipboard = navigator.clipboard;
        if (!clipboard || typeof clipboard.writeText !== "function" || window.isSecureContext === false) {
            let reason: string;
            if (!clipboard) {
                reason = "navigator.clipboard is not available";
            } else if (typeof clipboard.writeText !== "function") {
                reason = "navigator.clipboard.writeText is not a function";
            } else {
                reason = "page is not in a secure context (navigator.clipboard requires a secure context)";
            }
            useLogging && console.debug(
                `CONTENT_SHELL: ${reason}. Shell protection via navigator.clipboard.writeText patching is disabled, but copy event monitoring remains active.`
            );
            return;
        }
        // save the original writeText function
        const originalWriteText = clipboard.writeText.bind(clipboard);
        clipboard.writeText = async (data: string): Promise<void> => {
            try {
                if (ShellProtector.isSuspiciousText(data) && ShellProtector.isActive) {
                    ShellProtector.injectWarning();
                }
                useLogging && console.debug("CONTENT_SHELL: navigator.clipboard.writeText called with data:", data);
                return originalWriteText(data);
            } catch (error) {
                useLogging && console.error("CONTENT_SHELL: Error in patched writeText", error);
                // Re-throw to maintain original API behavior
                throw error;
            }
        };
        useLogging && console.debug("CONTENT_SHELL: Shell protection initialized.");
    }
}

// Start the script
ShellProtector.init();
